  ('disabled-7fec267e-moex-00110', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '羅聖朋和克拉夫丘克（D.H.Rosenbloom&R.S.Kravchuk）認為文官為主權 受託者，下列何者不屬於主權受託者應有的作為？', '["文官負責公共政策的制定與執行", "文官應動員政治支持為其政策倡議及辯護", "文官的決策應能符合商業團體的主要價值", "文官需具備旺盛的企圖心和長遠的眼光，以肆應未來的變遷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00111', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '以道德本身、道德判斷及道德原則作為研究對象的倫理研究，稱之為：', '["後設倫理學（metaethics）", "專業倫理學（professionalethics）", "法律倫理學（legalethics）", "行政倫理學（administrativeethics）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00112', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '我國為防制貪腐和促進廉能政府，已訂定相關陽光法令，但不包括下列何 者？', '["政治獻金法", "公務人員行政中立法", "遊說法", "公職人員利益衝突迴避法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00113', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '蝴蝶效應（butterflyeffect）意指某些因素的細微改變可能會導致後續巨大的 後果。此一概念符合下列何種組織理論的觀點？', '["組織是一種複雜適應系統", "組織是一種形塑宰制工具之系統", "組織是一種封閉型的系統", "組織是一種科學理性的系統"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00114', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '系統理論學者認為，組織內部包含了若干「次級系統」（sub-systems），下 列何者非屬次級系統所指涉的範疇？', '["正式結構", "自我終結", "專業知能", "使命與價值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00115', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '根據中央行政機關組織基準法之規定，機關依組織法規將其部分權限及職掌 劃出，以達成其設立目的之組織，謂之：', '["法人", "委員會", "公司", "機構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00116', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '奎恩（R.Quinn）和麥克葛雷斯（M.McGrath）把組織文化分成四類，下列 何者符合「層級」的組織文化的特徵？', '["是典型的績效取向文化，強調社會公平的價值", "重視組織權力的集中與內部的整合，人員行為深受法規的約制", "偏好以授權與參與的方式，維繫內部的穩定和諧", "以抽象的遠景和領袖魅力，維持人員的工作士氣 30460"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00117', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '政府人事體制的改革，其中包含績效導向系統的發展，因而更強調員工的工 作成果。此種人事改革背後的理論基礎為：', '["月暈效應（Haloeffect）", "新公共管理", "破窗理論", "長尾效應（Longtaileffect）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00118', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '一種由高階主管負責計畫性的管理全組織，讓此一有計畫的介入與訓練來促 進組織解決問題和變革的過程，稱之為：', '["策略規劃", "組織發展", "管理發展", "經驗學習"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL),
  ('disabled-7fec267e-moex-00119', 'disabled-7fec267e', 'disabled-7fec267e-moex-113-3a7b2121', 'sub-disabled-7fec267e-04', NULL, 'single_choice', '過去在學界提出許多關於公共預算規模擴張的解釋，其中一個實證觀察指 出，當國家或社會遇到重大事件時，民眾較易支持增加稅收與支出以作為因 應，當事件結束後，支出規模卻已無法回復原先水準。以上實證觀察屬於下 列何者？', '["華格納法則（Wagner’sLaw）", "位移效果（DisplaceEffect）", "斷續均衡（PunctuatedEquilibrium）", "政治景氣循環（PoliticalBusinessCycle）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:43+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "301", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般行政"}'::jsonb, NULL)
